// ============================================================
// SHOPIFY ORDER PARSER — Production Grade
// Devise de référence : shop_money (USD)
// ============================================================

return items.map(item => {
  const order = item.json;

  // ─── Helpers ─────────────────────────────────────────────
  const shopMoney = (priceSet) =>
    priceSet?.shop_money?.amount != null
      ? parseFloat(priceSet.shop_money.amount)
      : 0;

  const safeStr = (val) =>
    (val !== null && val !== undefined && val !== '') ? String(val).trim() : null;

  // ─── Line Items ──────────────────────────────────────────
  const products = (order.line_items || []).map(li => ({
    line_item_id:     li.id,
    product_id:       li.product_id   || null,
    variant_id:       li.variant_id   || null,
    name:             safeStr(li.title),
    variant:          safeStr(li.variant_title),
    sku:              safeStr(li.sku),
    quantity:         li.quantity,
    unit_price:       shopMoney(li.price_set),
    total_line_price: shopMoney(li.price_set) * li.quantity,
    total_discount:   shopMoney(li.total_discount_set),
    weight_grams:     li.grams || 0,
    is_custom_item:   li.product_id === null,
    is_gift_card:     li.gift_card || false,
    requires_shipping: li.requires_shipping || false,
    fulfillment_status: safeStr(li.fulfillment_status),
    // Propriétés custom (ex: gravure, personnalisation)
    custom_properties: (li.properties || []).length > 0
      ? li.properties.map(p => ({ key: p.name, value: p.value }))
      : null
  }));

  // ─── Livraison ───────────────────────────────────────────
  const shippingLine = (order.shipping_lines || [])[0] || null;

  // ─── Admin URL ───────────────────────────────────────────
  let shopDomain = null;
  if (order.order_status_url) {
    shopDomain = order.order_status_url.split('/')[2];
  } else if (order.admin_graphql_api_id) {
    // Fallback : extraire depuis le gid
    // gid://shopify/Order/123 → on ne peut pas récupérer le domaine ici
    // On utilise une constante connue du store
    shopDomain = 'YOUR_STORE.myshopify.com';
  }
  const adminUrl = shopDomain
    ? `https://${shopDomain}/admin/orders/${order.id}`
    : null;

  // ─── Payment Terms ───────────────────────────────────────
  const paymentTerms = order.payment_terms
    ? {
        name:        safeStr(order.payment_terms.payment_terms_name),
        type:        safeStr(order.payment_terms.payment_terms_type),
        due_in_days: order.payment_terms.due_in_days || null,
        due_at:      order.payment_terms.payment_schedules?.[0]?.due_at || null,
        paid_at:     order.payment_terms.payment_schedules?.[0]?.completed_at || null
      }
    : null;

  // ─── Résumé financier ────────────────────────────────────
  const subtotal    = shopMoney(order.current_subtotal_price_set);
  const shipping    = shippingLine ? shopMoney(shippingLine.price_set) : 0;
  const tax         = shopMoney(order.current_total_tax_set);
  const discounts   = shopMoney(order.current_total_discounts_set);
  const total       = shopMoney(order.current_total_price_set);

  return {
    json: {

      // ── Identité commande ─────────────────────────────────
      order_id:           order.id,
      order_number:       order.name,
      confirmation_number: safeStr(order.confirmation_number),
      source:             safeStr(order.source_name),
      tags:               safeStr(order.tags),
      created_at:         order.created_at,
      processed_at:       order.processed_at,
      updated_at:         order.updated_at,

      // ── Finance ───────────────────────────────────────────
      financial_status:   order.financial_status,
      is_paid:            order.financial_status === 'paid',
      currency:           order.currency,
      display_currency:   order.presentment_currency,
      subtotal:           subtotal,
      shipping_cost:      shipping,
      shipping_method:    safeStr(shippingLine?.title),
      total_tax:          tax,
      total_discounts:    discounts,
      total:              total,
      total_outstanding:  parseFloat(order.total_outstanding || 0),
      payment_methods:    order.payment_gateway_names || [],
      payment_terms:      paymentTerms,

      // ── Client ────────────────────────────────────────────
      customer: {
        id:           order.customer?.id || null,
        first_name:   safeStr(order.customer?.first_name),
        last_name:    safeStr(order.customer?.last_name),
        full_name:    [order.customer?.first_name, order.customer?.last_name]
                        .filter(Boolean).join(' ').trim() || null,
        email:        safeStr(order.email) || safeStr(order.contact_email),
        phone:        safeStr(order.phone) || safeStr(order.customer?.phone),
        locale:       safeStr(order.customer_locale),
        is_vip:       order.customer?.tags?.split(',').map(t => t.trim()).includes('VIP') || false,
        accepts_marketing: order.buyer_accepts_marketing || false
      },

      // ── Adresse livraison ─────────────────────────────────
      shipping_address: order.shipping_address
        ? {
            full_name: [order.shipping_address.first_name, order.shipping_address.last_name]
                         .filter(Boolean).join(' ').trim() || null,
            address1:  safeStr(order.shipping_address.address1),
            address2:  safeStr(order.shipping_address.address2),
            city:      safeStr(order.shipping_address.city),
            zip:       safeStr(order.shipping_address.zip),
            province:  safeStr(order.shipping_address.province),
            country:   safeStr(order.shipping_address.country),
            country_code: safeStr(order.shipping_address.country_code)
          }
        : null,

      // ── Produits ──────────────────────────────────────────
      products:           products,
      total_items_count:  products.reduce((sum, p) => sum + p.quantity, 0),
      total_weight_grams: order.total_weight || 0,
      has_custom_items:   products.some(p => p.is_custom_item),
      has_gift_cards:     products.some(p => p.is_gift_card),

      // ── Liens ─────────────────────────────────────────────
      order_status_url: safeStr(order.order_status_url),
      admin_url:        adminUrl
    }
  };
});

// ============================================================
// COMPUTE & CHECK SHEET WEEK
// Format : WEEK{n}_{yyyy} — ex: WEEK16_2026
// Basé sur ISO 8601 UTC — semaine commence le lundi
// ============================================================

const now = new Date();
const year  = now.getUTCFullYear();
const month = now.getUTCMonth();
const date  = now.getUTCDate();

// ─── Numéro de semaine ISO (standard, éprouvé) ────────────
// Algorithme : trouver le jeudi de la semaine courante,
// car en ISO 8601 c'est le jeudi qui "définit" la semaine
const iso = new Date(Date.UTC(year, month, date));
iso.setUTCDate(iso.getUTCDate() + 4 - (iso.getUTCDay() || 7));
const yearStart  = new Date(Date.UTC(iso.getUTCFullYear(), 0, 1));
const weekNumber = Math.ceil((((iso - yearStart) / 86400000) + 1) / 7);
const weekYear   = iso.getUTCFullYear(); // important : peut différer de year en W1/W52

// ─── Nom final ────────────────────────────────────────────
const computedName = `WEEK${weekNumber}_${weekYear}`;
const storedName   = $input.first().json.sheet_name;

return [{
  json: {
    stored_name:   storedName,   // "WEEK16_2026"
    computed_name: computedName, // "WEEK16_2026"
    week_changed:  computedName !== storedName
  }
}];

const items = $input.all();

// ─── Grouper par order_id ─────────────────────────────────
const ordersMap = {};

for (const item of items) {
  const d = item.json;
  const oid = d.order_id;

  if (!ordersMap[oid]) {
    ordersMap[oid] = {
      order_number:     d.order_number,
      created_at:       d.created_at,
      customer_name:    d.customer_name,
      customer_email:   d.customer_email,
      is_vip:           d.is_vip,
      shipping_country: d.shipping_country || 'N/A',
      payment_method:   d.payment_method,
      currency:         d.currency,
      tags:             d.tags || '',
      line_items:       [],
      order_total:      0,
      order_discount:   0,
    };
  }

  ordersMap[oid].line_items.push({
    product_name:     d.product_name,
    variant:          d.variant          || '',
    sku:              d.sku              || '',
    quantity:         d.quantity,
    unit_price:       d.unit_price,
    total_line_price: d.total_line_price,
    total_discount:   d.total_discount,
    is_custom_item:   d.is_custom_item,
  });

  ordersMap[oid].order_total    = Math.round((ordersMap[oid].order_total    + d.total_line_price) * 100) / 100;
  ordersMap[oid].order_discount = Math.round((ordersMap[oid].order_discount + d.total_discount)   * 100) / 100;
}

const orders = Object.values(ordersMap);

// ─── KPIs ─────────────────────────────────────────────────
const total_revenue      = Math.round(orders.reduce((s, o) => s + o.order_total,    0) * 100) / 100;
const total_discounts    = Math.round(orders.reduce((s, o) => s + o.order_discount, 0) * 100) / 100;
const vip_count          = orders.filter(o => o.is_vip).length;
const total_line_items   = orders.reduce((s, o) => s + o.line_items.length, 0);
const custom_items_count = orders.reduce((s, o) => s + o.line_items.filter(l => l.is_custom_item).length, 0);

// ─── Métadonnées ──────────────────────────────────────────
const sheet_name    = $('Get sheet name for branch2 from Redis').first().json.sheet_name_branch2;
const run_timestamp = items[0]?.json?.inserted_at || new Date().toISOString();

// ─── Alerte volume ────────────────────────────────────────
const VOLUME_THRESHOLD = 50;
const volume_alert     = orders.length > VOLUME_THRESHOLD
  ? `⚠ ${orders.length} orders received — threshold ${VOLUME_THRESHOLD} exceeded`
  : null;

// ─── Output ───────────────────────────────────────────────
return [{
  json: {
    sheet_name,
    run_timestamp,
    volume_alert,
    kpis: {
      orders_count:        orders.length,
      total_line_items,
      total_revenue,
      total_discounts,
      vip_count,
      custom_items_count,
    },
    orders,
  }
}];

