// ============================================================
// SHEETS ROW BUILDER — One row per line item
// Input  : Shopify Order Parser output (N orders)
// Output : M rows (one per line item, ready for Sheets append)
// ============================================================

const rows = [];
const insertedAt = new Date().toISOString();

for (const item of items) {
  const o = item.json;

  // ─── Métadonnées commande (répétées sur chaque ligne) ────
  const orderMeta = {
    inserted_at:     insertedAt,
    order_id:        o.order_id,
    order_number:    o.order_number,
    created_at:      o.created_at,
    customer_name:   o.customer?.full_name   || "Guest",   // jamais null
    customer_email:  o.customer?.email       ?? null,
    is_vip:          o.customer?.is_vip      ?? false,
    shipping_country: o.shipping_address?.country_code ?? null,
    payment_method:  (o.payment_methods || []).join(", ") || null,
    currency:        o.currency              ?? null,
    tags:            o.tags                  ?? "",        // jamais null
  };

  // ─── Une ligne par line item ─────────────────────────────
  for (const product of (o.products || [])) {
    rows.push({
      json: {
        ...orderMeta,

        // Données line item
        line_item_id:     product.line_item_id    ?? null,
        product_name:     product.name            ?? null,
        variant:          product.variant         ?? null,
        sku:              product.sku              ?? "",   // jamais null
        quantity:         product.quantity        ?? null,
        unit_price:       product.unit_price      ?? null,
        total_line_price: product.total_line_price ?? null,
        total_discount:   product.total_discount  ?? null,
        is_custom_item:   product.is_custom_item  ?? false,
      }
    });
  }
}

return rows;
